import{fetchUsers,formatUser}from"./utils/api.js";import{debounce,groupBy}from"./modules/helpers.js";const init=async()=>{try{const o=await fetchUsers(),e=o.map(formatUser);console.log(`Załadowano ${e.length} użytkowników`);const s=o[0]?.name??"Brak nazwy";console.log(`Pierwszy użytkownik: ${s}`);const t=groupBy(e,"city");console.log("Grupowanie po mieście:",t);return debounce(o=>{console.log(`Szukam: ${o}`)},300)("test"),{users:e,byCity:t}}catch(o){console.error("Błąd inicjalizacji:",o.message)}};init();